import numpy as np

def _mlp(x, layers):
    for idx, (W, b) in enumerate(layers):
        x = x @ W.T + b
        if idx < len(layers) - 1:
            x = np.maximum(0, x)
        else:
            x = 1.0 / (1.0 + np.exp(-x))
    return x

def cgan_generator(
    z: np.ndarray,
    label: int,
    n_classes: int,
    gen_layers: list[tuple[np.ndarray, np.ndarray]]
) -> np.ndarray:
    one_hot = np.zeros(n_classes)
    one_hot[label] = 1.0
    inp = np.concatenate([z, one_hot])
    return _mlp(inp, gen_layers)

def cgan_discriminator(
    x: np.ndarray,
    label: int,
    n_classes: int,
    dis_layers: list[tuple[np.ndarray, np.ndarray]]
) -> float:
    one_hot = np.zeros(n_classes)
    one_hot[label] = 1.0
    inp = np.concatenate([x, one_hot])
    return float(_mlp(inp, dis_layers).squeeze())
